mapper.select:
SELECT r.*, u.nick_name, u.avatar_url, c.name as category_name
FROM records r
LEFT JOIN users u ON r.user_id = u.id
LEFT JOIN categories c ON r.category_id = c.id
WHERE r.ledger_id = #{ledgerId}

    AND r.type = #{type}


    AND r.category_id = #{categoryId}


    AND r.record_date >= #{startDate}


    AND r.record_date <= #{endDate}

ORDER BY r.record_date DESC, r.created_at DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM records r
WHERE r.ledger_id = #{ledgerId}

    AND r.type = #{type}


    AND r.category_id = #{categoryId}


    AND r.record_date >= #{startDate}


    AND r.record_date <= #{endDate}

SELECT type, SUM(amount) as total, COUNT(*) as count
FROM records
WHERE ledger_id = #{ledgerId}

    AND record_date >= #{startDate}


    AND record_date <= #{endDate}

GROUP BY type

SELECT c.name as category_name, r.type, SUM(r.amount) as total, COUNT(*) as count
FROM records r
LEFT JOIN categories c ON r.category_id = c.id
WHERE r.ledger_id = #{ledgerId}

    AND r.record_date >= #{startDate}


    AND r.record_date <= #{endDate}

GROUP BY r.category_id, r.type
ORDER BY total DESC

SELECT u.nick_name, u.avatar_url, r.type, SUM(r.amount) as total, COUNT(*) as count
FROM records r
JOIN users u ON r.user_id = u.id
WHERE r.ledger_id = #{ledgerId}

    AND r.record_date >= #{startDate}


    AND r.record_date <= #{endDate}

GROUP BY r.user_id, r.type
ORDER BY total DESC

SELECT DATE(record_date) as date, type, SUM(amount) as total
FROM records
WHERE ledger_id = #{ledgerId}

    AND record_date >= #{startDate}


    AND record_date <= #{endDate}

GROUP BY DATE(record_date), type
ORDER BY date DESC
LIMIT 60
